class Solution {
public:
    int numberOfSubstrings(string s) {
        int countA = 0, countB = 0, countC = 0;
        int result = 0;
        for (char c : s) {
            if (c == 'a') countA++;
            if (c == 'b') countB++;
            if (c == 'c') countC++;
            result += min({countA, countB, countC});
        }
        return result;
    }
};
```
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
